mapper.select:
SELECT A.NWHOIS_SEQ , A.SSVC_LINE_TYPE_CD , A.NLVL_MST_SEQ , A.SASSIGN_TYPE_CD , A.SWHOISREQUESTID , A.SAPPLICATIONNAME , A.PIP_PREFIX , A.SFIRST_ADDR , A.SLAST_ADDR , A.NFIRST_ADDR , A.NLAST_ADDR , A.NCNT , A.SREQUEST_CD , A.SWHOISRESULT_CD , A.SWHOISRESULT_MSG , A.SKRNICMEMBER_ID , A.SISP_NM , A.SSAID , A.SLLNM , A.SNET_NM , A.SSCRETE_YN , A.SUSERORGGB , A.SNETTYPE , A.SSERVICEGB , A.SSVCLOC , A.SHOSTNOW , A.SUSEDTLNOW , A.SHOST6MONTH , A.SUSEDTL6MONTH , A.SHOST12MONTH , A.SUSEDTL12MONTH , A.SSVCCOMMNET , A.SREMARK , A.DSEND_DT , A.DRECEIPT_DT , A.DRECEIPTOK_DT , A.DREPLY_DT , A.DREGOK_DT , A.SKRNICNO , A.SKRNICORGCODE , A.SOLD_NET , A.SOLD_TOT_SUBNET , A.SOLD_TOT_HOST , A.SOLD_COMMENT , A.SNET_PLAN , A.STOT_SUBNET , A.STOT_HOST , A.SSVCNETWORK , A.SCITY , A.SCCLASSIP , A.SCREATE_ID , A.DCREATE_DT , A.SMODIFY_ID , A.DMODIFY_DT, A.SIP_TYPE , B.SNETNAME , B.SORGNAME , B.SADDR , NVL(B.SADDR_DETAIL, ' ') AS SADDR_DETAIL, B.SZIPCODE , B.SEORGNAME , B.SEADDR , NVL(B.SEADDR_DETAIL, ' ') AS SEADDR_DETAIL, B.SADM_NAME , B.SADM_ORGNAME , B.SADM_ADDR , B.SADM_ADDR_DETAIL , B.SADM_ZIPCODE , B.SADM_ENAME , B.SADM_EORGNAME , B.SADM_EADDR , B.SADM_EADDR_DETAIL , B.SADM_PHONE , B.SADM_DPPHONE , B.SADM_FAX , B.SADM_EMAIL , B.SFLAG , B.SADDRSEQ , B.SSERIALNO , B.SADM_SERIALNO , B.SECITY , B.SORGTYPE , B.SCUSTNAME FROM BIF.TB_WHOIS A LEFT JOIN BIF.TB_WHOIS_USER B ON B.SSAID = A.SSAID WHERE 1 = 1
AND A.NWHOIS_SEQ = #{nwhoisSeq, jdbcType=BIGINT}
AND A.SWHOISREQUESTID = #{swhoisrequestid, jdbcType=VARCHAR}
ORDER BY A.NWHOIS_SEQ

SELECT A.NWHOIS_SEQ , A.SSVC_LINE_TYPE_CD , A.NLVL_MST_SEQ , A.SASSIGN_TYPE_CD , A.SWHOISREQUESTID , A.SAPPLICATIONNAME , A.PIP_PREFIX , A.SFIRST_ADDR , A.SLAST_ADDR , A.NFIRST_ADDR , A.NLAST_ADDR , A.NCNT , A.SREQUEST_CD , A.SWHOISRESULT_CD , A.SWHOISRESULT_MSG , A.SKRNICMEMBER_ID , A.SISP_NM , A.SSAID , A.SLLNM , A.SNET_NM , A.SSCRETE_YN , A.SUSERORGGB , A.SNETTYPE , A.SSERVICEGB , A.SSVCLOC , A.SHOSTNOW , A.SUSEDTLNOW , A.SHOST6MONTH , A.SUSEDTL6MONTH , A.SHOST12MONTH , A.SUSEDTL12MONTH , A.SSVCCOMMNET , A.SREMARK , A.DSEND_DT , A.DRECEIPT_DT , A.DRECEIPTOK_DT , A.DREPLY_DT , A.DREGOK_DT , A.SKRNICNO , A.SKRNICORGCODE , A.SOLD_NET , A.SOLD_TOT_SUBNET , A.SOLD_TOT_HOST , A.SOLD_COMMENT , A.SNET_PLAN , A.STOT_SUBNET , A.STOT_HOST , A.SSVCNETWORK , A.SCITY , A.SCCLASSIP , A.SCREATE_ID , A.DCREATE_DT , A.SMODIFY_ID , A.DMODIFY_DT, A.SIP_TYPE , B.SNETNAME , B.SORGNAME , B.SADDR , B.SADDR_DETAIL , B.SZIPCODE , B.SEORGNAME , B.SEADDR , B.SEADDR_DETAIL , B.SADM_NAME , B.SADM_ORGNAME , B.SADM_ADDR , B.SADM_ADDR_DETAIL , B.SADM_ZIPCODE , B.SADM_ENAME , B.SADM_EORGNAME , B.SADM_EADDR , B.SADM_EADDR_DETAIL , B.SADM_PHONE , B.SADM_DPPHONE , B.SADM_FAX , B.SADM_EMAIL , B.SFLAG , B.SADDRSEQ , B.SSERIALNO , B.SADM_SERIALNO , B.SECITY , B.SORGTYPE , B.SCUSTNAME FROM BIF.TB_WHOIS A LEFT OUTER JOIN BIF.TB_WHOIS_USER B ON B.SSAID = A.SSAID WHERE 1 = 1
AND A.NWHOIS_SEQ = #{nwhoisSeq, jdbcType=BIGINT}
AND A.SWHOISREQUESTID = #{swhoisrequestid, jdbcType=VARCHAR}
ORDER BY NWHOIS_SEQ

SELECT NRESULT FROM(
	SELECT BIF.UF_NEW_WHOIS(
		#{nipAllocMstSeq,	jdbcType=OTHER, typeHandler=com.kt.ipms.legacy.cmn.typehandler.BigIntTypeHandler}
		, #{type,	jdbcType=VARCHAR}
		, #{sessionId,	jdbcType=VARCHAR}
	) AS NRESULT)

mapper.update:
UPDATE BIF.TB_WHOIS A SET
			A.SMODIFY_ID = #{smodifyId, jdbcType=VARCHAR}
			, A.DMODIFY_DT = CURRENT_TIMESTAMP

				, A.SREQUEST_CD = #{srequestCd, jdbcType=VARCHAR}


				, A.SWHOISRESULT_CD = #{swhoisresultCd, jdbcType=VARCHAR}


				, A.SWHOISRESULT_MSG = #{swhoisresultMsg, jdbcType=VARCHAR}

		WHERE 
			A.NWHOIS_SEQ = #{nwhoisSeq, jdbcType=BIGINT}

UPDATE BIF.TB_WHOIS_USER A SET A.SMODIFY_ID = #{smodifyId, jdbcType=VARCHAR} , A.DMODIFY_DT = CURRENT_TIMESTAMP
, A.SORGNAME = #{sorgname, jdbcType=VARCHAR}
, A.SADDR = #{saddr, jdbcType=VARCHAR}
, A.SADDR_DETAIL = #{saddrDetail, jdbcType=VARCHAR}
, A.SZIPCODE = #{szipcode, jdbcType=VARCHAR}
, A.SEORGNAME = #{seorgname, jdbcType=VARCHAR}
, A.SEADDR = #{seaddr, jdbcType=VARCHAR}
, A.SEADDR_DETAIL = #{seaddrDetail, jdbcType=VARCHAR}
, A.SCITY = CASE WHEN LEFT(#{saddr, jdbcType=VARCHAR},2) = '서울' THEN '서울' WHEN LEFT(#{saddr, jdbcType=VARCHAR},2) = '인천' THEN '인천' WHEN LEFT(#{saddr, jdbcType=VARCHAR},2) = '부산' THEN '부산' WHEN LEFT(#{saddr, jdbcType=VARCHAR},2) = '대전' THEN '대전' WHEN LEFT(#{saddr, jdbcType=VARCHAR},2) = '광주' THEN '광주' WHEN LEFT(#{saddr, jdbcType=VARCHAR},2) = '울산' THEN '울산' WHEN LEFT(#{saddr, jdbcType=VARCHAR},2) = '제주' THEN '제주' WHEN LEFT(#{saddr, jdbcType=VARCHAR},2) = '강원' THEN '강원' WHEN LEFT(#{saddr, jdbcType=VARCHAR},2) = '대구' THEN '대구' WHEN LEFT(#{saddr, jdbcType=VARCHAR},2) = '경기' THEN '경기' WHEN LEFT(#{saddr, jdbcType=VARCHAR},4) = '충청북도' THEN '충북' WHEN LEFT(#{saddr, jdbcType=VARCHAR},4) = '충청남도' THEN '충남' WHEN LEFT(#{saddr, jdbcType=VARCHAR},4) = '경상남도' THEN '경남' WHEN LEFT(#{saddr, jdbcType=VARCHAR},4) = '경상북도' THEN '경북' WHEN LEFT(#{saddr, jdbcType=VARCHAR},4) = '전라남도' THEN '전북' WHEN LEFT(#{saddr, jdbcType=VARCHAR},4) = '전라북도' THEN '전남' ELSE '경기' END
, A.SECITY = UPPER(bif.uf_convert_han_to_eng(CASE WHEN LEFT(#{saddr, jdbcType=VARCHAR},2) = '서울' THEN '서울' WHEN LEFT(#{saddr, jdbcType=VARCHAR},2) = '인천' THEN '인천' WHEN LEFT(#{saddr, jdbcType=VARCHAR},2) = '부산' THEN '부산' WHEN LEFT(#{saddr, jdbcType=VARCHAR},2) = '대전' THEN '대전' WHEN LEFT(#{saddr, jdbcType=VARCHAR},2) = '광주' THEN '광주' WHEN LEFT(#{saddr, jdbcType=VARCHAR},2) = '울산' THEN '울산' WHEN LEFT(#{saddr, jdbcType=VARCHAR},2) = '제주' THEN '제주' WHEN LEFT(#{saddr, jdbcType=VARCHAR},2) = '강원' THEN '강원' WHEN LEFT(#{saddr, jdbcType=VARCHAR},2) = '대구' THEN '대구' WHEN LEFT(#{saddr, jdbcType=VARCHAR},2) = '경기' THEN '경기' WHEN LEFT(#{saddr, jdbcType=VARCHAR},4) = '충청북도' THEN '충북' WHEN LEFT(#{saddr, jdbcType=VARCHAR},4) = '충청남도' THEN '충남' WHEN LEFT(#{saddr, jdbcType=VARCHAR},4) = '경상남도' THEN '경남' WHEN LEFT(#{saddr, jdbcType=VARCHAR},4) = '경상북도' THEN '경북' WHEN LEFT(#{saddr, jdbcType=VARCHAR},4) = '전라남도' THEN '전북' WHEN LEFT(#{saddr, jdbcType=VARCHAR},4) = '전라북도' THEN '전남' ELSE '경기' END , 'Y'))
FROM BIF.TB_WHOIS B WHERE A.SSAID = B.SSAID AND SPLIT_PART(A.SSAID, '-', 1) = SPLIT_PART(#{ssaid, jdbcType=VARCHAR}, '-', 1)

mapper.delete:
DELETE FROM BIF.TB_WHOIS A
WHERE
	A.NWHOIS_SEQ = #{nwhoisSeq, jdbcType=BIGINT}

mapper.select:
SELECT NRESULT FROM(
	SELECT BIF.UF_NEW_WHOIS_LOG(
		#{swhoisrequestid,	jdbcType=VARCHAR}
		, #{sresultmsg,	jdbcType=VARCHAR}
	) AS NRESULT)

SELECT A.SSVC_LINE_TYPE_CD , C.SSVC_GROUP_CD , C.SSVC_OBJ_CD , A.PIP_PREFIX , A.SIP_BLOCK , A.NBITMASK FROM MST.TB_IP_ASSIGN_MST A , MST.TB_IP_ALLOC_MST B , MST.TB_LVL_MST C , BIF.TB_WHOIS D WHERE 1=1 AND B.NIP_ASSIGN_MST_SEQ(+) = A.NIP_ASSIGN_MST_SEQ AND C.NLVL_MST_SEQ = A.NLVL_MST_SEQ AND D.SSVC_LINE_TYPE_CD(+) = A.SSVC_LINE_TYPE_CD AND D.NLVL_MST_SEQ(+) = A.NLVL_MST_SEQ AND D.PIP_PREFIX(+) = A.PIP_PREFIX
AND B.NIP_ALLOC_MST_SEQ = #{nipAllocMstSeq, jdbcType=BIGINT}
AND D.NWHOIS_SEQ = #{nwhoisSeq, jdbcType=BIGINT}

SELECT A.nip_alloc_mst_cnt FROM MST.TB_IP_ASSIGN_MST A, BIF.TB_WHOIS B WHERE 1=1 AND B.PIP_PREFIX(+) = A.PIP_PREFIX
AND B.NWHOIS_SEQ = #{nwhoisSeq, jdbcType=BIGINT}
limit 1
